import React, { useState } from "react";
import { motion } from "framer-motion";

const AnimatedSection = ({ children, style }) => {
  const [clicked, setClicked] = useState(false);

  return (
    <motion.section
      initial={{ backgroundColor: "transparent", scale: 1 }}
      whileHover={{ backgroundColor: "#4CAF50", color: "#ffffff" }} // fondo verde fuerte, texto claro
      animate={{ scale: clicked ? 1.12 : 1 }}
      transition={{ duration: clicked ? 0.15 : 0.3 }}
      onClick={() => {
        setClicked(true);
        setTimeout(() => setClicked(false), 200); // vuelve a la normalidad rápido
      }}
      style={{
        cursor: "pointer",
        borderRadius: "1rem",
        boxShadow: "0 4px 15px rgba(0,0,0,0.1)",
        padding: "2rem",
        maxWidth: "1400px",
        margin: "0 auto 6rem",
        flexWrap: "wrap",
        color: "black",
        ...style,
      }}
    >
      {children}
    </motion.section>
  );
};

export default AnimatedSection;
